import React, { useState, useEffect } from 'react';
import { Link, useLocation, useNavigate } from 'react-router-dom';
import { ShoppingCart, Menu, X, Phone, LogIn, LogOut, LayoutDashboard, User } from 'lucide-react';
import toast from 'react-hot-toast';
import { useCart } from '../lib/CartContext';
import { useAuth } from '../lib/AuthContext';
import { signOut } from '../lib/supabase';
import './Navbar.css';

const NAV_LINKS = [
  { to: '/',            label: 'Home'      },
  { to: '/menu',        label: 'Menu'      },
  { to: '/gallery',     label: 'Gallery'   },
  { to: '/reservation', label: 'Reserve'   },
  { to: '/about',       label: 'Our Story' },
  { to: '/reviews',     label: 'Reviews'   },
];

export default function Navbar({ onCartOpen }) {
  const { totalItems }           = useCart();
  const { user, isAdmin }        = useAuth();
  const [scrolled, setScrolled]  = useState(false);
  const [mobileOpen, setMobile]  = useState(false);
  const { pathname }             = useLocation();
  const navigate                 = useNavigate();

  useEffect(() => {
    const onScroll = () => setScrolled(window.scrollY > 40);
    window.addEventListener('scroll', onScroll);
    return () => window.removeEventListener('scroll', onScroll);
  }, []);

  useEffect(() => { setMobile(false); }, [pathname]);

  const handleLogout = async () => {
    await signOut();
    toast.success('Signed out successfully.');
    navigate('/');
  };

  const isHome = pathname === '/';

  return (
    <>
      <nav className={`navbar ${scrolled || !isHome ? 'navbar--solid' : ''}`}>
        <div className="navbar__inner">
          <Link to="/" className="navbar__logo">
            <span className="navbar__logo-icon">🍜</span>
            <span className="navbar__logo-text">
              <span className="navbar__logo-main">BurmeseBites</span>
              <span className="navbar__logo-sub">Authentic Myanmar Cuisine</span>
            </span>
          </Link>

          <ul className="navbar__links">
            {NAV_LINKS.map(({ to, label }) => (
              <li key={to}>
                <Link to={to} className={`navbar__link ${pathname === to ? 'navbar__link--active' : ''}`}>
                  {label}
                </Link>
              </li>
            ))}
          </ul>

          <div className="navbar__actions">
            <a href="tel:+66012345678" className="navbar__phone">
              <Phone size={14} /><span>+66 01 234 5678</span>
            </a>

            {user ? (
              <div className="navbar__user-menu">
                {isAdmin && (
                  <Link to="/admin" className="navbar__admin-link" title="Admin Dashboard">
                    <LayoutDashboard size={15} /> Admin
                  </Link>
                )}
                <div className="navbar__user-avatar" title={user.email}>
                  {(user.user_metadata?.full_name || user.email).charAt(0).toUpperCase()}
                </div>
                <button className="navbar__logout" onClick={handleLogout} title="Sign out">
                  <LogOut size={16} />
                </button>
              </div>
            ) : (
              <Link to="/auth" className="navbar__login">
                <LogIn size={15} /> Sign In
              </Link>
            )}

            <button className="navbar__cart" onClick={onCartOpen} aria-label="Open cart">
              <ShoppingCart size={20} />
              {totalItems > 0 && <span className="navbar__cart-badge">{totalItems}</span>}
            </button>

            <button className="navbar__mobile-toggle" onClick={() => setMobile(v => !v)} aria-label="Toggle menu">
              {mobileOpen ? <X size={22} /> : <Menu size={22} />}
            </button>
          </div>
        </div>
      </nav>

      <div className={`mobile-drawer ${mobileOpen ? 'mobile-drawer--open' : ''}`}>
        <ul className="mobile-drawer__links">
          {NAV_LINKS.map(({ to, label }) => (
            <li key={to}>
              <Link to={to} className={`mobile-drawer__link ${pathname === to ? 'mobile-drawer__link--active' : ''}`}>
                {label}
              </Link>
            </li>
          ))}
          {user ? (
            <>
              {isAdmin && (
                <li><Link to="/admin" className="mobile-drawer__link">🛠 Admin Dashboard</Link></li>
              )}
              <li>
                <button className="mobile-drawer__link" style={{ width:'100%', textAlign:'left', cursor:'pointer' }} onClick={handleLogout}>
                  Sign Out
                </button>
              </li>
            </>
          ) : (
            <li><Link to="/auth" className="mobile-drawer__link">Sign In / Create Account</Link></li>
          )}
          <li>
            <button className="btn btn-primary mobile-drawer__order" onClick={onCartOpen}>
              Order Online
            </button>
          </li>
        </ul>
      </div>
      {mobileOpen && <div className="mobile-overlay" onClick={() => setMobile(false)} />}
    </>
  );
}
